from collections import Counter
import math

class Solution(object):
    def minOperations(self, nums):
        freq = Counter(nums)
        ops = 0
        for cnt in freq.values():
            if cnt == 1:
                return -1
            ops += math.ceil(cnt / 3)
        return ops
